module test_case (
  input  wire         clk,
  input  wire         rst_clk,
  output wire [32:0]  rd [8:0],
  input  wire  [5:0]  wa [8:0],
  input  wire  [8:0]  wen
);

  logic [63:0][32:0] big;
  logic [63:0][32:0] wd;
  logic [5:0]        ra [8:0];

  always @(posedge clk) begin
      if (rst_clk) begin
        big <= '0;
      end
      else begin
        for (int i = 0; i < 9; i++) begin
          if (wen[i]) big[wa[i]] <= wd[wa[i]];
        end
      end
  end

  generate
    for (genvar i = 0; i < 9; i++) begin
      assign rd[i] = big[ra[i]];
    end
  endgenerate

endmodule
